        // Сначала создаем все главы
        $chaptersData = [
            // Глава 1 и её подглавы
            ['number' => '1', 'title' => 'ОСНОВНАЯ ЦЕЛЬ И ОБЛАСТЬ ПРИМЕНЕНИЯ', 'content' => 'Лазерный CO2 станок WATTSAN предназначен для высокоточной резки и гравировки неметаллических материалов.', 'parent_id' => 0, 'level' => 0, 'order' => 1],
            ['number' => '1.1', 'title' => 'Основная цель', 'content' => 'Лазерный CO2 станок WATTSAN предназначен для высокоточной резки и гравировки неметаллических материалов с применением лазерного излучения. Данное оборудование позволяет автоматизировать и оптимизировать процессы обработки материалов с высоким качеством и точностью. Станок позволяет выполнять как серийное, так и мелкосерийное производство изделий различной сложности с минимальными затратами времени и ресурсов.', 'parent_id' => 0, 'level' => 0, 'order' => 2],
            ['number' => '1.2', 'title' => 'Основные требования эксплуатации', 'content' => "1) Подключенное заземление: сопротивление заземления <5 Ω.\n2) Требуется установка стабилизатора напряжения сети, обеспечивающего стабилизацию напряжения станка.\n3) Требуется хорошая вентиляция для предотвращения скопления пыли и продуктов горения.\n4) Для охлаждения лазерного источника и лазерной головы, необходимо правильно настроить и контролировать работу чиллера. Это специализированное оборудование, охлаждающее и циркулирующую воду, и требует использования только дистиллированной воды.\n5) Эксплуатация оборудования допускается, только с подключенной системой подачи сжатого воздуха или вспомогательного газа.\n6) Для предотвращения пожара рабочее место должно быть оборудовано подходящим огнетушителем.\n7) Вокруг станка должна быть свободное пространство около 1 м с каждой стороны.", 'parent_id' => 0, 'level' => 0, 'order' => 3],
            ['number' => '1.3', 'title' => 'Воздействие на окружающую среду и людей', 'content' => 'Лазерный станок относится к IV классу лазерного оборудования. Его лазерный луч и отражённый свет могут вызывать повреждение человеческого тела (особенно глаз). Оператору и рабочему персоналу следует обратить внимание на защиту глаз и использовать специальные очки (с защитой от излучения с диапазоном длины волны 10600 нм).', 'parent_id' => 0, 'level' => 0, 'order' => 4],

            // Глава 2 и её подглавы
            ['number' => '2', 'title' => 'ИНСТРУКЦИЯ ПО ТЕХНИКЕ БЕЗОПАСНОСТИ', 'content' => 'Перед началом эксплуатации станка и ежедневным обслуживанием оператор должен внимательно прочитать эту главу, изучить меры безопасности и требования к станку.', 'parent_id' => 0, 'level' => 0, 'order' => 5],
            ['number' => '2.1', 'title' => 'Обзор', 'content' => 'Перед началом эксплуатации станка и ежедневным обслуживанием оператор должен внимательно прочитать эту главу, изучить меры безопасности и требования к станку, а также соблюдать соответствующие меры предосторожности.', 'parent_id' => 0, 'level' => 0, 'order' => 6],
            ['number' => '2.2', 'title' => 'Обеспечение безопасности работы с оборудованием', 'content' => "1) Необходимо назначить специалиста по обеспечению промышленной безопасности при эксплуатации оборудования, определить объем его обязанностей и выполнить обучение по технике безопасности для оператора станка.\n2) Укажите зону размещения станка, установите предупреждающую карту входа и выхода из зоны размещения станка, указав: мощность станка, тип лазерного источника, тип используемой защиты для глаз, ФИО специалиста по обеспечению промышленной безопасности и т.д.\n3) Оператор станка должен получить специальную подготовку.", 'parent_id' => 0, 'level' => 0, 'order' => 7],
            ['number' => '2.3', 'title' => 'Предупреждение о безопасности при работе с лазером', 'content' => 'Никогда не направляйте лазерный луч на людей или животных. Лазерное излучение высокой мощности может вызвать серьезные ожоги или повредить зрение. Всегда следите за направлением луча и контролируйте его движение.', 'parent_id' => 0, 'level' => 0, 'order' => 8],
            ['number' => '2.3.1', 'title' => 'Защита глаз и кожи', 'content' => 'Лазерное излучение может повредить сетчатку глаза. Лазер может вызвать катаракту глаза и ожоги кожи. Поэтому при регулировке лазера применяются соответствующие защитные меры. Этот станок оснащен СО2 лазерным источником, поэтому, при работе с открытой крышкой, необходимо носить специальные защитные очки (с защитой от излучения с диапазоном длины волны 10600 нм).', 'parent_id' => 0, 'level' => 0, 'order' => 9],
            ['number' => '2.3.2', 'title' => 'Противопожарная защита', 'content' => 'Искрообразование при работе может легко вызвать пожар. Поэтому в рабочей зоне станка не должно быть огнеопасных и взрывоопасных предметов. Огнетушители должны быть поблизости и доступны, а персонал обучен их использованию.', 'parent_id' => 0, 'level' => 0, 'order' => 10],
            ['number' => '2.3.3', 'title' => 'Опасность вторичного излучения', 'content' => 'Во время гравировки и резки возникает как видимое, так и невидимое световое излучение. Взаимодействие между лазерным излучением высокой мощности и свариваемыми материалами может создавать плазму, которая производит УФ-излучение и "синий свет", который может вызвать конъюнктивит, фотохимическое повреждение сетчатки. Во избежание последствий излучения необходимо работать с закрытой крышкой.', 'parent_id' => 0, 'level' => 0, 'order' => 11],
            ['number' => '2.3.4', 'title' => 'Опасность отравления дымом', 'content' => 'Дым, выделяемый от материала во время лазерной обработки, может состоять из очень мелких частиц и газов. Дым может негативно повлиять на легкие, сердце, почки и центральную нервную систему. Всегда выполняйте работу в зоне с достаточной вентиляцией. Используйте систему удаления дыма для удаления паров, частиц и опасного мусора из зоны работы станка.', 'parent_id' => 0, 'level' => 0, 'order' => 12],
            ['number' => '2.4', 'title' => 'Электробезопасность', 'content' => "1) Убедитесь, что установка правильно заземлена.\n2) Перед подачей питания на установку убедитесь, что используется правильное напряжение источника переменного тока.\n3) Никогда не используйте устройство во влажной или мокрой среде.\n4) Не открывайте электрический шкаф и не изменяйте параметры станка без согласования с руководством.\n5) Всегда выключайте устройство, когда оно не используется.\n6) После отключения питания станка необходимо выждать не менее 5 минут.", 'parent_id' => 0, 'level' => 0, 'order' => 13],
            ['number' => '2.5', 'title' => 'Обязанности оператора', 'content' => "• Оператор должен пройти специальную подготовку, чтобы приступить к работе на станке.\n• Следуйте инструкциям по регулярному техническому обслуживанию устройства, чтобы поддерживать его в рабочем состоянии и предотвратить аварийные ситуации.\n• Запрещается работать на неисправном оборудовании. В случае обнаружения неисправности, выключите оборудование и отключите его от сети.", 'parent_id' => 0, 'level' => 0, 'order' => 14],
            ['number' => '2.6', 'title' => 'Материалы для обработки', 'content' => "• Перед обработкой, оператор должен убедиться в том, что материал пригоден для обработки.\n• Запрещается обрабатывать на оборудовании тефлон, поливинилхлорид (ПВХ), гетинакс, фторопласт, винил, любые другие фтор-, хлор-, бром-, йод-, астат-содержащие материалы, так как газ, выделяемый при резке чрезвычайно вреден для здоровья человека, и портит механику и оптику вашего оборудования.\n• Запрещено обрабатывать материалы с высоким коэффициентом отражения в ИК-спектре.\n• Перед обработкой материалов оператор должен проверить, могут ли образовываться вредные вещества при их обработке.", 'parent_id' => 0, 'level' => 0, 'order' => 15],

            // Глава 3
            ['number' => '3', 'title' => 'ТРАНСПОРТИРОВКА И УСТАНОВКА', 'content' => 'Сохраните упаковочную коробку. Она понадобится вам в случае возврата.', 'parent_id' => 0, 'level' => 0, 'order' => 16],
            ['number' => '3.1', 'title' => 'Приемка', 'content' => "1) Сохраните упаковочную коробку. Она понадобится вам в случае возврата.\n2) После вскрытия упаковки, проверьте комплектацию.\n3) Проверьте оборудования на наличие повреждений при транспортировке.\n\nВ первую очередь внимательно осмотрите лазерную трубку на предмет сколов или битого стекла, как внутри лазерной трубки, так и снаружи. Это самая хрупкая часть в вашем оборудовании!", 'parent_id' => 0, 'level' => 0, 'order' => 17],
            ['number' => '3.2', 'title' => 'Установка', 'content' => "• Станок должен быть установлен на ровной поверхности без скосов и уклонов. Необходимо оставить свободное пространство по бокам станка от 1м.\n• Пространство вокруг станка должно быть освобождено, для быстрого и беспрепятственного доступа к панели и другим компонентам станка.", 'parent_id' => 0, 'level' => 0, 'order' => 18],
            ['number' => '3.3', 'title' => 'Требования к помещению', 'content' => "1. Температура окружающей среды: от +10°С до +40°С. При выключении оборудования не ниже +4°С.\n2. Влажность: относительная влажность воздуха <70%.\n3. Запрещается использовать оборудование при относительной влажности более 70%.\n4. Охлаждение электрических компонентов осуществляется за счет циркуляции воздуха. Важно, чтобы детали внутри шкафа были не загрязнены пылью и грязью.", 'parent_id' => 0, 'level' => 0, 'order' => 19],

            // Глава 4
            ['number' => '4', 'title' => 'УСТРОЙСТВО ОБОРУДОВАНИЯ', 'content' => 'Станок лазерной резки Wattsan состоит из следующих основных узлов.', 'parent_id' => 0, 'level' => 0, 'order' => 20],
            ['number' => '4.1', 'title' => 'Внешний вид', 'content' => 'Станок имеет защитный кожух, панель управления, рабочую зону с лазерной головой, систему охлаждения и вытяжки.', 'parent_id' => 0, 'level' => 0, 'order' => 21],
            ['number' => '4.2', 'title' => 'Основные узлы станка', 'content' => "1. Двигатель подъемного стола\n2. Корпус станка\n3. Винт подъемного стола\n4. Поддон для сбора мусора\n5. Колесо ножки станка\n6. Рабочий стол\n7. Ножка станка\n8. Антивибрационная опора ножки станка\n9. Крепление лазерной трубки\n10. Лазерная трубка\n11. Двигатель оси Y\n12. Опора ременной передачи\n13. Зубчатый ремень\n14. Редуктор в сборе\n15. Вал оси Y\n16. Зубчатый ремень\n17. Направляющая\n18. Зеркало №1, №2, №3\n19. Лазерная голова\n20. Балка портала станка\n21. Двигатель оси X\n22. Редуктор в сборе\n23. Опора ременной передачи\n24. Концевой индуктивный датчик\n25. Линейный подшипник\n26. Датчик протока воды\n27. Блок высокого напряжения", 'parent_id' => 0, 'level' => 0, 'order' => 22],
            ['number' => '4.3', 'title' => 'Панель управления', 'content' => "Reset — перезагрузка системы\nStart/Pause — запуск/пауза\nPulse — тестовый импульс\nStop — остановка\nFocus — автофокус\nMenu — меню настроек\nFrame — обводка области обработки\nFile — доступ к файлам\nOrigin — установка нулевой точки\nPower — установка мощности\nSpeed — установка скорости\nСтрелки — перемещение головы\nZ↑/Z↓ — движение по оси Z\nU+/U- — движение по оси U", 'parent_id' => 0, 'level' => 0, 'order' => 23],

            // Глава 5
            ['number' => '5', 'title' => 'УСТАНОВКА ОБОРУДОВАНИЯ', 'content' => 'Пошаговая инструкция по установке всех компонентов станка.', 'parent_id' => 0, 'level' => 0, 'order' => 24],
            ['number' => '5.1', 'title' => 'Установка опор', 'content' => 'К станку прилагаются 4 опоры и крепеж для его установки. Приподнимите станок поочередно с каждой стороны, установите опоры и закрепите через специальные отверстия в корпусе. После перемещения станка на требуемое место, рекомендуется зафиксировать его с помощью ножек.', 'parent_id' => 0, 'level' => 0, 'order' => 25],
            ['number' => '5.2', 'title' => 'Установка лазерной трубки', 'content' => 'Перед установкой проверьте полупрозрачное зеркало на загрязнение. Установите трубку выходным отверстием к первому зеркалу. Штуцер отвода воды должен смотреть вверх. Подключите шланги подачи и отвода воды. Высоковольтные провода надежно заизолируйте.', 'parent_id' => 0, 'level' => 0, 'order' => 26],
            ['number' => '5.3', 'title' => 'Установка воздушного компрессора', 'content' => 'Распакуйте компрессор, установите штуцер. Закрепите силиконовый шланг на штуцер. Второй конец шланга подключите в Air inlet разъём на станке. Закрепите шланг стяжкой.', 'parent_id' => 0, 'level' => 0, 'order' => 27],
            ['number' => '5.4', 'title' => 'Установка системы охлаждения', 'content' => 'Распакуйте чиллер, установите возле станка. Открутите сливную пробку, очистите бак, залейте дистиллированную воду. Подключите шланги Inlet/Outlet. Подключите кабель питания.', 'parent_id' => 0, 'level' => 0, 'order' => 28],
            ['number' => '5.5', 'title' => 'Установка системы вытяжки', 'content' => 'Распакуйте вентилятор. Подключите гофрошланг к нижней части станка, второй конец к вентилятору. Третий шланг от вентилятора к системе вентиляции или на улицу.', 'parent_id' => 0, 'level' => 0, 'order' => 29],
            ['number' => '5.6', 'title' => 'Подключение заземления', 'content' => 'На станке есть специальное место для заземления. Зафиксируйте кабель на металлическом винте. Второй конец подключите к точке общего заземления.', 'parent_id' => 0, 'level' => 0, 'order' => 30],

            // Глава 6
            ['number' => '6', 'title' => 'НАСТРОЙКА И ЭКСПЛУАТАЦИЯ', 'content' => 'Первый запуск станка должен производить специалист.', 'parent_id' => 0, 'level' => 0, 'order' => 31],
            ['number' => '6.1', 'title' => 'Подготовка чиллера', 'content' => 'Очистите резервуар, залейте дистиллированную воду. Убедитесь, что уровень воды в зеленой зоне. Запустите чиллер, проверьте поток воды, отсутствие пузырей воздуха. Дождитесь достижения заданной температуры.', 'parent_id' => 0, 'level' => 0, 'order' => 32],
            ['number' => '6.2', 'title' => 'Порядок включения оборудования', 'content' => "1. На передней панели повернуть по часовой стрелке кнопку аварийного отключения\n2. Включить питание системы управления\n3. Включить питание лазера\n4. Включить питание чиллера и компрессора\n5. Повернуть ключ в положение ON (он отвечает за включение лазерного излучателя)", 'parent_id' => 0, 'level' => 0, 'order' => 33],
            ['number' => '6.3', 'title' => 'Порядок отключения станка', 'content' => "1. Повернуть ключ активации лазера в положение OFF\n2. Выключить питание системы управления\n3. Выключить питание лазера\n4. Выключить питание чиллера и компрессора\n5. Зажмите кнопку аварийной остановки", 'parent_id' => 0, 'level' => 0, 'order' => 34],
            ['number' => '6.4', 'title' => 'Очистка оптических элементов', 'content' => 'Используйте ватные палочки (желательно безворсовые) и жидкость для очистки оптики (ацетон высокой чистоты или изопропиловый спирт). Не используйте воду, этанол или метиловый спирт.', 'parent_id' => 0, 'level' => 0, 'order' => 35],
            ['number' => '6.5', 'title' => 'Натяжение зубчатых ремней', 'content' => 'Проверяйте натяжку каждое утро. Ремень должен поворачиваться на 360 градусов вокруг оси, но не более. Если ремень провисает или слишком натянут — отрегулируйте.', 'parent_id' => 0, 'level' => 0, 'order' => 36],
            ['number' => '6.6', 'title' => 'Установка ламелей', 'content' => 'Ламели вставляются в специальные пазы на рабочем столе основанием вниз. Рекомендуется устанавливать с пробелом в 2 паза.', 'parent_id' => 0, 'level' => 0, 'order' => 37],
            ['number' => '6.7', 'title' => 'Юстировка', 'content' => 'Юстировку проводите при первом запуске и ежедневно перед началом работы.', 'parent_id' => 0, 'level' => 0, 'order' => 38],
            ['number' => '6.7.1', 'title' => 'Настройка первого зеркала', 'content' => 'У каждого крепления зеркала есть латунные винты, которые регулируют угол наклона. Верхний винт регулирует угол наклона по вертикали, а правый и левый – по горизонтали и диагонали.', 'parent_id' => 0, 'level' => 0, 'order' => 39],
            ['number' => '6.7.2', 'title' => 'Настройка второго зеркала', 'content' => 'Принцип регулировки тот же, что и на предыдущем этапе. Важно, чтобы луч приходил в центр зеркала.', 'parent_id' => 0, 'level' => 0, 'order' => 40],
